(771, '_elementor_onboarding_strings_es_ES', 'a:2:{s:7:\"timeout\";i:1776940650;s:5:\"value\";s:5254:\"{\"common.continue\":\"Continuar\",\"common.skip\":\"Omitir\",\"common.back\":\"Atr\\u00e1s\",\"common.finish\":\"Finalizar\",\"common.loading\":\"Cargando\\u2026\",\"common.upgrade\":\"Actualizar\",\"common.close_onboarding\":\"Cerrar la incorporaci\\u00f3n\",\"common.installed\":\"Instalado\",\"common.recommended\":\"Recomendado\",\"error.failed_mark_exit\":\"No se pudo marcar la salida del usuario.\",\"error.failed_complete_step\":\"No se pudo completar el paso.\",\"error.pro_install_failed\":\"No se pudo instalar Elementor Pro. Int\\u00e9ntelo de nuevo m\\u00e1s tarde.\",\"error.theme_install_failed\":\"La instalaci\\u00f3n del tema no se complet\\u00f3. Int\\u00e9ntelo de nuevo m\\u00e1s tarde.\",\"login.title\":\"\\u00a1Manos a la obra!\",\"login.sign_in\":\"Iniciar sesi\\u00f3n en Elementor\",\"login.continue_another_way\":\"Continuar de otra manera\",\"login.continue_as_guest\":\"Continuar como invitado\",\"steps.building_for.title\":\"\\u00bfPara qui\\u00e9n est\\u00e1 creando?\",\"steps.building_for.greeting_with_name\":\"Hola, %1$s %2$s. Vamos a configurar su sitio.\",\"steps.building_for.greeting_without_name\":\"Hola, %s. Vamos a configurar su sitio.\",\"steps.building_for.option_myself\":\"Para m\\u00ed o para alguien que conozco\",\"steps.building_for.option_business\":\"Para mi negocio o lugar de trabajo\",\"steps.building_for.option_client\":\"Para un cliente\",\"steps.building_for.option_exploring\":\"Solo estoy explorando\",\"steps.site_about.title\":\"\\u00bfDe qu\\u00e9 trata su sitio?\",\"steps.site_about.subtitle\":\"Elija todo lo que corresponda.\",\"steps.site_about.option_small_med_business\":\"Peque\\u00f1a o mediana empresa\",\"steps.site_about.option_online_store\":\"Tienda online\",\"steps.site_about.option_company_site\":\"Sitio web de empresa\",\"steps.site_about.option_blog\":\"Blog\",\"steps.site_about.option_landing_page\":\"P\\u00e1gina de destino\",\"steps.site_about.option_booking\":\"Reservas\",\"steps.site_about.option_organization\":\"Organizaci\\u00f3n\",\"steps.site_about.option_other\":\"Otro\",\"steps.site_about.greeting_myself\":\"\\u00a1Entendido! Lo mantendremos simple.\",\"steps.site_about.greeting_business\":\"\\u00a1Genial! Vamos a configurar su sitio web de negocios.\",\"steps.site_about.greeting_client\":\"\\u00a1Bien! Vamos a crear algo para su cliente.\",\"steps.site_about.greeting_fallback\":\"\\u00a1Empecemos!\",\"steps.experience_level.title\":\"\\u00bfQu\\u00e9 experiencia tiene con Elementor?\",\"steps.experience_level.subtitle\":\"Esto nos ayuda a ajustar el editor a su flujo de trabajo.\",\"steps.experience_level.option_beginner\":\"Estoy empezando\",\"steps.experience_level.option_intermediate\":\"Tengo algo de experiencia\",\"steps.experience_level.option_advanced\":\"Me siento muy c\\u00f3modo con Elementor\",\"steps.theme_selection.title\":\"Empiece con un tema que se adapte a sus necesidades\",\"steps.theme_selection.subtitle\":\"Los temas Hello est\\u00e1n dise\\u00f1ados para funcionar a la perfecci\\u00f3n con Elementor.\",\"steps.theme_selection.aria_label\":\"Selecci\\u00f3n de tema\",\"steps.theme_selection.theme_hello_label\":\"Hello\",\"steps.theme_selection.theme_hello_description\":\"Un tema de lienzo flexible que puede moldear desde cero\",\"steps.theme_selection.theme_hello_biz_label\":\"Hello Biz\",\"steps.theme_selection.theme_hello_biz_description\":\"Un tema listo para usar con dise\\u00f1os y widgets inteligentes\",\"steps.theme_selection.greeting_beginner\":\"\\u00a1Me alegro de que est\\u00e9 aqu\\u00ed!\",\"steps.theme_selection.greeting_default\":\"Genial. Pasemos al siguiente paso.\",\"steps.theme_selection.continue_with_theme\":\"Continuar con este tema\",\"steps.site_features.title\":\"\\u00bfQu\\u00e9 desea incluir en su sitio?\",\"steps.site_features.subtitle\":\"Usaremos la informaci\\u00f3n para personalizar sugerencias para usted..\",\"steps.site_features.continue_with_free\":\"Continuar con la versi\\u00f3n gratuita\",\"steps.site_features.option_classes_variables\":\"Sistema de dise\\u00f1o\",\"steps.site_features.option_interactions\":\"Interacciones\",\"steps.site_features.option_theme_builder\":\"Constructor de temas\",\"steps.site_features.option_lead_collection\":\"Formularios y clientes potenciales\",\"steps.site_features.option_custom_code\":\"C\\u00f3digo personalizado\",\"steps.site_features.option_email_deliverability\":\"Entrega de correo electr\\u00f3nico\",\"steps.site_features.option_ai_generator\":\"Herramientas de IA\",\"steps.site_features.option_image_optimization\":\"Optimizaci\\u00f3n de im\\u00e1genes\",\"steps.site_features.option_accessibility_tools\":\"Accesibilidad\",\"steps.site_features.woocommerce\":\"WooCommerce\",\"steps.site_features.included\":\"Incluido\",\"steps.site_features.plan_recommendation_one\":\"Buenas elecciones \\ud83d\\ude42 Elementor One las incluye..\",\"steps.site_features.plan_recommendation_pro\":\"\\u00bfHerramientas avanzadas? Elementor Pro las incluye.\",\"steps.site_features.compare_plans\":\"Ver planes\",\"pro_install.title\":\"Ya tiene una suscripci\\u00f3n Pro\",\"pro_install.subtitle\":\"\\u00bfLe gustar\\u00eda instalarla en este sitio ahora?\",\"pro_install.installing\":\"Instalando Elementor Pro\\u2026\",\"pro_install.installing_short\":\"Instalando\\u2026\",\"pro_install.install_button\":\"Instalar Pro en este sitio\",\"pro_install.logo_alt\":\"Elementor + Elementor Pro\",\"pro_install.do_it_later\":\"Lo har\\u00e9 m\\u00e1s tarde\",\"completion.title\":\"Preparando todo\",\"completion.subtitle\":\"Personalizando el editor a sus necesidades y flujo de trabajo\"}\";}', 'off'),
